FUNCTION Manhattan-Distance(state, goal):
 total ← 0

 FOR each tile in state:
 IF tile = blank:
 CONTINUE

 // Find position of tile in current state
 (row1, col1) ← position(state, tile)

 // Find position of tile in goal state
 (row2, col2) ← position(goal, tile)

 // Add vertical + horizontal distance
 distance ← |row1 - row2| + |col1 - col2|
 total ← total + distance

 RETURN total

// Example: Tile 5 at (1,2) in state, (2,3) in goal
// Distance = |1-2| + |2-3| = 1 + 1 = 2
